// Expand persisted alerts for per-item Telegram dispatch.
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];
return items
  .filter(i => (i.channels || []).includes('telegram'))
  .map(item => ({ json: item }));

// Format the alert as a Telegram message using HTML parse mode.
// All dynamic fields are HTML-escaped to prevent parse errors or injection.
const item = $input.item.json;

const escHtml = (s) =>
  (s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');

const topicEmoji = {
  crypto:     '🪙',
  finance:    '📈',
  economy:    '🏦',
  health:     '🏥',
  ai:         '🤖',
  energy:     '⚡',
  technology: '💻'
};
const emoji = topicEmoji[item.topic_slug] || '📰';
const importanceBar = '🟩'.repeat(Math.round(item.importance_score / 20)) + '⬜'.repeat(5 - Math.round(item.importance_score / 20));
const sourceLink = item.source_url
  ? `\n<a href="${escHtml(item.source_url)}">Source: ${escHtml(item.source_name)}</a>`
  : `\nSource: ${escHtml(item.source_name)}`;

const text = [
  `${emoji} <b>${item.topic_slug.toUpperCase()}</b>  |  Importance: ${importanceBar} ${item.importance_score}/100`,
  ``,
  `<b>${escHtml(item.headline)}</b>`,
  ``,
  escHtml(item.summary_text),
  sourceLink
].join('\n');

return [{ json: { ...item, telegram_text: text } }];

